import React, { createContext, useContext, useState } from "react";
import { Languages } from "../components/utils/dmdb.props";

interface LanguageContextType {
    language: Languages;
    setLanguage: React.Dispatch<React.SetStateAction<Languages>>,
}

const UserPreferenceContext = createContext({} as LanguageContextType);

export default function LanguageProvider( {children}: any ) {
  const [language, setLanguage] = useState<Languages>(getLanguageFromLocalStorage());

  return (
    <UserPreferenceContext.Provider
      value={{
        language,
        setLanguage,
      }}
    >
      {children}
    </UserPreferenceContext.Provider>
  );
}

export function useLanguage() {
    const { language, setLanguage } = useContext(UserPreferenceContext);
    return { language, setLanguage };
}

function getLanguageFromLocalStorage(){
    const language = localStorage.getItem('dmdb-language')

    if (language && (language === "enus" || language === "ptbr")) {
        return language;
    }

    return "enus";
}
